def process_transactions(transactions):
    # Create a dictionary to store the updated account balances
    accounts = {}

    # Iterate over each transaction
    for transaction in transactions:
        # Get the account number and amount of the transaction
        account, amount = transaction["account"], transaction["amount"]

        # Check if the account is already in the dictionary
        if account not in accounts:
            # If it's not, create a new entry for the account with an initial balance of 0
            accounts[account] = 0

        # Update the account balance by adding the amount of the transaction
        accounts[account] += amount

    return accounts